func solve(s string) []string {
	var segments []string
	seen := make(map[string]bool)
	n := len(s)
	for i := 0; i < n; {
		current := ""
		for j := i; j < n; j++ {
			current += string(s[j])
			if !seen[current] {
				segments = append(segments, current)
				seen[current] = true
				i = j + 1
				break
			}
			if j == n-1 {
				segments = append(segments, current)
				i = n
			}
		}
	}
	return segments
}
